summary:
Пиццерия рядом со мной кладёт пепперони «как получится» — равномерно, но не так, как хочется. Идеал: каждый кусок и каждый укус одинаково «случайны», но в меру.  

Сделаем такую пиццу в браузере.

### Равномерное распределение

```js
const randUniform = () => 2 * Math.random() - 1;

function uniformPepperoni() {
  const [cx, cy, r] = pepperoniBounds();
  let x, y;
  do {
    x = randUniform() * r;
    y = randUniform() * r;
  } while (x * x + y * y >= r * r);
  return [cx + x, cy + y];
}

for (let i = 0; i < 300; i++) {
  const [x, y] = uniformPepperoni();
  drawPepperoni(x, y);
}
```

### Нормальное распределение

Используем преобразование Бокса–Мюллера:

```js
function randNormal() {
  const θ = 2 * Math.PI * Math.random();
  const r = Math.sqrt(-2 * Math.log(Math.random()));
  return [r * Math.cos(θ), r * Math.sin(θ)];
}

function normalPepperoni() {
  const [cx, cy, r] = pepperoniBounds();
  let x, y;
  do {
    [x, y] = randNormal();
    x = cx + x * r / 3;
    y = cy + y * r / 3;
  } while ((x - cx) ** 2 + (y - cy) ** 2 >= r * r);
  return [x, y];
}
```

### Кластеры

Добавим несколько «горстей» пепперони в случайных точках:

```js
function clusterPepperoni(cx, cy) {
  const [_, _, r] = pepperoniBounds();
  let x, y;
  do {
    [x, y] = randNormal();
    x = cx + x * r / 3;
    y = cy + y * r / 3;
  } while ((x - cx) ** 2 + (y - cy) ** 2 >= r * r);
  return [x, y];
}

for (let c = 0; c < 3; c++) {
  const [cx, cy] = randomClusterCenter();
  for (let i = 0; i < 100; i++) {
    const [x, y] = clusterPepperoni(cx, cy);
    drawPepperoni(x, y);
  }
}
```

Теперь пицца выглядит «как у местных» — немного хаотично, но с акцентами.
